<template><view class="page"><xy-header title="我的" variant="brand" :show-back="false"/><view class="profile"><text class="name">{{me.nickname||'微信会员'}}</text><text>{{me.mobile||'未绑定手机号'}}</text><text>{{me.card?`${me.card.planName} · ${me.card.expireDate}到期`:'未开通会员'}}</text></view><view class="menu"><view v-for="item in menus" :key="item.url" @click="go(item.url)">{{item.label}}<text>›</text></view></view><view class="xy-tabbar-hold"></view><xy-tabbar active="mine"/></view></template>
<script>import{appRequest,ensureMemberSession,showRequestError}from'../../utils/api';export default{data(){return{me:{},menus:[{label:'会员卡',url:'/pages/membership/card'},{label:'会员资料',url:'/pages/membership/profile'},{label:'我的预约',url:'/pages/reserve/history'},{label:'我的订单',url:'/pages/order/list'},{label:'我的账单',url:'/pages/bills/bills'},{label:'收货地址',url:'/pages/order/address'},{label:'邀请好友',url:'/pages/invite/invite'}]}},onShow(){this.load()},methods:{async load(){try{await ensureMemberSession();this.me=await appRequest({url:'/app/me'})}catch(e){showRequestError(e)}},go(url){uni.navigateTo({url})}}}</script><style scoped>.page{min-height:100vh;background:var(--xy-bg)}.profile{display:flex;flex-direction:column;gap:12rpx;padding:40rpx;color:#fff;background:var(--xy-primary)}.name{font-size:38rpx;font-weight:700}.menu{margin:24rpx;border-radius:22rpx;background:#fff}.menu view{display:flex;justify-content:space-between;padding:28rpx;border-bottom:1rpx solid var(--xy-hairline)}</style>
